import '@testing-library/jest-dom';
// This file was generated by an AI agent. Do not edit directly.
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import type { RenderResult } from '@testing-library/react';
import { Button } from './Button';
import type { ButtonProps } from './Button';

function getInnerWrapper(root: HTMLElement): HTMLSpanElement {
  const el = root.querySelector<HTMLSpanElement>(':scope > span');
  if (!el) {
    throw new Error(
      'Expected Button to render an inner wrapper <span> as the first child of the root button'
    );
  }
  return el;
}

type Variant = NonNullable<ButtonProps['variant']>;

describe('Button', () => {
  it('renders label', () => {
    const view: RenderResult = render(<Button label="Click me" />);
    expect(screen.getByRole('button', { name: 'Click me' })).toBeInTheDocument();
    view.unmount();
  });

  it('renders start icon slot', () => {
    const view: RenderResult = render(
      <Button label="Go" startIcon={<span data-testid="start">⭐</span>} />
    );
    expect(screen.getByTestId('start')).toBeInTheDocument();
    view.unmount();
  });

  it('renders end icon slot', () => {
    const view: RenderResult = render(
      <Button label="Go" endIcon={<span data-testid="end">➡️</span>} />
    );
    expect(screen.getByTestId('end')).toBeInTheDocument();
    view.unmount();
  });

  describe('applies variant classes on the inner wrapper (visuals), not the root button', () => {
    const cases: ReadonlyArray<[label: string, variant: Variant, expectedClass: string]> = [
      ['Primary', 'primary', 'bg-comp-button-primary-color-background-default'],
      ['Secondary', 'secondary', 'bg-comp-button-secondary-color-background-default'],
      ['Bare', 'bare', 'text-comp-button-bare-color-foreground-default'],
      ['Knockout', 'knockout', 'border-comp-button-knockout-color-border-default']
    ] as const;

    it.each(cases)('applies %s variant', (label, variant, expectedClass) => {
      const view: RenderResult = render(<Button label={label} variant={variant} />);
      const root = screen.getByRole('button', { name: label });
      const wrapper = getInnerWrapper(root);
      expect(wrapper).toHaveClass(expectedClass);
      view.unmount();
    });
  });

  it('fullWidth adds w-full class on the inner wrapper', () => {
    const view: RenderResult = render(<Button label="Wide" fullWidth />);
    const root = screen.getByRole('button', { name: 'Wide' });
    const wrapper = getInnerWrapper(root);
    expect(wrapper).toHaveClass('w-full');
    view.unmount();
  });

  it('includes focus ring token class on the root button', () => {
    const view: RenderResult = render(<Button label="Focus" />);
    const root = screen.getByRole('button', { name: 'Focus' });
    expect(root.className).toMatch(/focus-visible:ring-comp-button-focus-color-ring/);
    view.unmount();
  });
});
